/**
 * Generates a shields.io "endpoint" badge JSON file from Istanbul's
 * coverage-summary.json, so the README's coverage badge is regenerated by CI
 * on every push to main instead of being a hand-typed number that can go
 * stale. The badge shows the LOWEST of the four coverage categories
 * (statements/branches/functions/lines) — a single "100%" claim should mean
 * all four, not just the easiest one.
 *
 * Usage: npm run coverage && node scripts/generate-coverage-badge.js
 */

const fs = require("fs");
const path = require("path");

const SUMMARY_PATH = path.join(__dirname, "..", "coverage", "coverage-summary.json");
const OUTPUT_DIR = path.join(__dirname, "..", "badges");
const OUTPUT_PATH = path.join(OUTPUT_DIR, "coverage.json");

function colorFor(pct) {
  if (pct >= 95) return "brightgreen";
  if (pct >= 85) return "green";
  if (pct >= 70) return "yellowgreen";
  if (pct >= 50) return "yellow";
  return "red";
}

function main() {
  if (!fs.existsSync(SUMMARY_PATH)) {
    console.error(`Missing ${path.relative(process.cwd(), SUMMARY_PATH)}. Run "npm run coverage" first.`);
    process.exitCode = 1;
    return;
  }

  const summary = JSON.parse(fs.readFileSync(SUMMARY_PATH, "utf8"));
  const total = summary.total;
  const categories = ["statements", "branches", "functions", "lines"];
  const pctByCategory = Object.fromEntries(categories.map((c) => [c, total[c].pct]));
  const worst = Math.min(...Object.values(pctByCategory));

  const badge = {
    schemaVersion: 1,
    label: "coverage",
    message: `${worst}%`,
    color: colorFor(worst),
  };

  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
  fs.writeFileSync(OUTPUT_PATH, JSON.stringify(badge, null, 2) + "\n");

  console.log(`Coverage by category: ${JSON.stringify(pctByCategory)}`);
  console.log(`Badge (lowest category, ${worst}%) written to ${path.relative(process.cwd(), OUTPUT_PATH)}`);
}

main();
